@@ -14,9 +14,9 @@ type MessageDeduplicator struct {
 	maxSize   int
 }

-// NewMessageDeduplicator creates a deduplicator with the given max capacity.
-// When capacity is reached, the oldest entries are not evicted (simple set).
-// For witness sessions that process hundreds of messages at most, this is fine.
+// NewMessageDeduplicator creates a deduplicator with the given capacity hint.
+// The map may grow beyond this size — 10k string keys is negligible memory,
+// and correctness (no duplicate processing) matters more than a soft cap.
 func NewMessageDeduplicator(maxSize int) *MessageDeduplicator {
 	if maxSize <= 0 {
 		maxSize = 10000
@@ -41,11 +41,6 @@ func (d *MessageDeduplicator) AlreadyProcessed(messageID string) bool {
 		return true
 	}

-	// Don't grow unboundedly
-	if len(d.processed) >= d.maxSize {
-		return false // At capacity, allow processing (safe: worst case is a dup)
-	}
-
 	d.processed[messageID] = true
 	return false
 }

@@ -56,20 +56,25 @@ func TestMessageDeduplicator_Size(t *testing.T) {
 	}
 }

-func TestMessageDeduplicator_MaxSize(t *testing.T) {
+func TestMessageDeduplicator_BeyondCapacity(t *testing.T) {
 	t.Parallel()
 	d := NewMessageDeduplicator(3)

 	d.AlreadyProcessed("msg-001")
 	d.AlreadyProcessed("msg-002")
 	d.AlreadyProcessed("msg-003")

-	// At capacity — new messages should still be allowed (not deduped)
+	// Beyond capacity — new messages should still be allowed and tracked
 	if d.AlreadyProcessed("msg-004") {
-		t.Error("at capacity, new messages should be allowed through")
+		t.Error("new message should be allowed through")
 	}

-	// But existing ones should still be detected
+	// The new message must be tracked so it's deduped on retry
+	if !d.AlreadyProcessed("msg-004") {
+		t.Error("msg-004 should be detected as duplicate after being processed")
+	}
+
+	// Original messages should still be detected
 	if !d.AlreadyProcessed("msg-001") {
 		t.Error("existing message should still be detected as duplicate")
 	}
